iner and self.widgetinfo and widgetbuttoninfo2 and widgetbuttoninfo2.validfn then if widgetbuttoninfo2.validfn(self.container) then self.button2:Enable() else self.button2:Disable() end end return retVal end local function DYCContainerWidget(self) self.dycOldOpen = self.Open self.Open = Open self.dycOldClose = self.Close self.Close = Close self.dycOldOnItemGet = self.OnItemGet self.OnItemGet = OnItemGet self.dycOldOnItemLose = self.OnItemLose self.OnItemLose = OnItemLose end return DYCContainerWidget 